            Reduziert
          </button>
        </div>

        {/* Bottom Row: Sub Filters */}
        {mainCat !== 'Alle' && subCats[mainCat] && (
          <div className="flex flex-wrap gap-2 justify-center">
            {subCats[mainCat].map(sub => (
              <button 
